package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    String expectedCurrencyCode = "USD";

    // Directly use the LineItem class instead of reflection to avoid ClassNotFoundException
    Constructor<LineItem> constructor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance("TestItem", 5, 1000L, expectedCurrencyCode);

    // Invoke getCurrencyCode method directly
    String actualCurrencyCode = lineItem.getCurrencyCode();

    assertEquals(expectedCurrencyCode, actualCurrencyCode);
  }
}
